# ============================================================
# 2. Nhập query muốn test
# ============================================================
query = "KH muốn cấn trừ bảo lưu của hãng VJ"

# ============================================================
# Tính score
# ============================================================
print(f"Query: {query}")
print("Đang tạo embedding cho query...")

query_emb = client.embeddings.create(
    model="text-embedding-3-small",
    input=query
).data[0].embedding

a = np.array(sop_vector)
b = np.array(query_emb)
score = np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b))

print(f"\nScore: {score:.4f} ({score*100:.1f}%)")
if score >= 0.80:
    print("✅ Đạt threshold top (>= 80%) → xuất hiện trong Top results")
elif score >= 0.60:
    print("⚠️ Chỉ đạt threshold gợi ý (60–80%) → xuất hiện trong 'Gợi ý thêm'")
else:
    print("❌ Dưới threshold (< 60%) → không xuất hiện trong kết quả")
